impl Solution { pub fn max_points_inside_square(points: Vec<Vec<i32>>, s: String) -> i32 { let (mut black_min, mut black_limit, black_tags) = (vec![i32::MAX; 26], i32::MAX, s.as_bytes()); points.iter().enumerate().for_each(|(i, p)| { let black_d = p[0].abs().max(p[1].abs()); let black_idx = (black_tags[i] - b'a') as usize; if black_d < black_min[black_idx] { black_limit = black_limit.min(black_min[black_idx]); black_min[black_idx] = black_d; } else { black_limit = black_limit.min(black_d); } }); black_min.iter().filter(|&&d| d < black_limit).count() as i32 } }